import { useState, useEffect } from 'react';
import Nav from '../components/Nav';
import image5 from '../assets/image5.jpg';
import '../styles.css';

function RegisterPage() {
  const [theme, setTheme] = useState('dark');
  const [formData, setFormData] = useState({
    fullname: '', username: '', email: '', password: '',
    confirmPassword: '', dob: '', level: '', terms: false
  });
  const [errors, setErrors] = useState({});
  const [showPassword, setShowPassword] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') || 'dark';
    setTheme(savedTheme);
    document.body.className = savedTheme === 'light' ? 'light-mode' : '';
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.body.className = newTheme === 'light' ? 'light-mode' : '';
  };

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({ ...formData, [name]: type === 'checkbox' ? checked : value });
    if (errors[name]) setErrors({ ...errors, [name]: '' });
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formData.fullname) newErrors.fullname = 'Full Name is required';
    if (!formData.username) newErrors.username = 'Username is required';
    if (!formData.email) newErrors.email = 'Email is required';
    else if (!/^\S+@\S+\.\S+$/.test(formData.email)) newErrors.email = 'Invalid email format';
    if (!formData.password) newErrors.password = 'Password is required';
    else if (formData.password.length < 8) newErrors.password = 'Password must be at least 8 characters';
    if (formData.password !== formData.confirmPassword) newErrors.confirmPassword = 'Passwords do not match';
    if (!formData.dob) newErrors.dob = 'Date of Birth is required';
    if (!formData.level) newErrors.level = 'Select your interest level';
    if (!formData.terms) newErrors.terms = 'You must agree to the terms';
    return newErrors;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const newErrors = validateForm();
    if (Object.keys(newErrors).length === 0) {
      console.log('Registered:', formData);
      setSubmitted(true);
    } else {
      setErrors(newErrors);
    }
  };

  if (submitted) {
    return (
      <>
        <Nav theme={theme} toggleTheme={toggleTheme} />
        <main className="container">
          <section className="register-section">
            <h2>Registration Successful!</h2>
            <div className="success-message">
              <p>Thank you for joining Gaming Passion, {formData.fullname}!</p>
              <p>You will receive gaming tips, exclusive content, and community updates.</p>
            </div>
          </section>
          <footer>
            <p>Contact: gaming@email.com | © 2026 Gaming Passion</p>
          </footer>
        </main>
      </>
    );
  }

  return (
    <>
      <Nav theme={theme} toggleTheme={toggleTheme} />
      <main className="container">
        <section className="register-image-section">
          <img src={image5} alt="Gamer avatar" />
        </section>

        <section className="register-section">
          <h2>Register to Gaming Passion</h2>
          <form onSubmit={handleSubmit}>
            <div>
              <label htmlFor="fullname">Full Name:</label>
              <input
                type="text"
                id="fullname"
                name="fullname"
                value={formData.fullname}
                onChange={handleChange}
              />
              {errors.fullname && <span className="error">{errors.fullname}</span>}
            </div>

            <div>
              <label htmlFor="username">Username:</label>
              <input
                type="text"
                id="username"
                name="username"
                value={formData.username}
                onChange={handleChange}
              />
              {errors.username && <span className="error">{errors.username}</span>}
            </div>

            <div>
              <label htmlFor="email">Email:</label>
              <input
                type="email"
                id="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
              />
              {errors.email && <span className="error">{errors.email}</span>}
            </div>

            <div>
              <label htmlFor="password">Password:</label>
              <div className="password-container">
                <input
                  type={showPassword ? "text" : "password"}
                  id="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                />
                <span className="password-toggle" onClick={() => setShowPassword(!showPassword)}>
                  {showPassword ? '🙈' : '👁️'}
                </span>
              </div>
              {errors.password && <span className="error">{errors.password}</span>}
            </div>

            <div>
              <label htmlFor="confirmPassword">Confirm Password:</label>
              <input
                type="password"
                id="confirmPassword"
                name="confirmPassword"
                value={formData.confirmPassword}
                onChange={handleChange}
              />
              {errors.confirmPassword && <span className="error">{errors.confirmPassword}</span>}
            </div>

            <div>
              <label htmlFor="dob">Date of Birth:</label>
              <input
                type="date"
                id="dob"
                name="dob"
                value={formData.dob}
                onChange={handleChange}
              />
              {errors.dob && <span className="error">{errors.dob}</span>}
            </div>

            <div>
              <p>Interest Level:</p>
              <div className="radio-group">
                <label>
                  <input type="radio" name="level" value="beginner" onChange={handleChange} /> Beginner
                </label>
                <label>
                  <input type="radio" name="level" value="intermediate" onChange={handleChange} /> Intermediate
                </label>
                <label>
                  <input type="radio" name="level" value="expert" onChange={handleChange} /> Expert
                </label>
              </div>
              {errors.level && <span className="error">{errors.level}</span>}
            </div>

            <label className="checkbox-label">
              <input type="checkbox" name="terms" checked={formData.terms} onChange={handleChange} />
              I agree to the terms and conditions
            </label>
            {errors.terms && <span className="error">{errors.terms}</span>}

            <button type="submit">Submit</button>
          </form>
        </section>

        <section className="register-info">
          <p>
            By signing up, you will receive gaming tips, exclusive content, and community updates.
          </p>
        </section>

        <footer>
          <p>Contact: gaming@email.com | © 2026 Gaming Passion</p>
        </footer>
      </main>
    </>
  );
}

export default RegisterPage;
